40	<script setup lang="ts">
41	import { ref, onMounted, onUnmounted, watch } from 'vue'
42	import { onShow } from '@dcloudio/uni-app'
43	import BatteryCircle from '@/pages/batteryCircle/batteryCircle.vue'
44	
45	// 从本地存储中获取电量数据
46	const leftPower = ref(0)
47	const rightPower = ref(0)
48	const leftModel = ref('')
49	const rightModel = ref('')
50	const leftSerialNo = ref('')
51	const rightSerialNo = ref('')
52	const leftConnected = ref(false)
53	const rightConnected = ref(false)
54	
55	// 定期刷新电量数据的定时器
56	let refreshTimer: number | null = null
57	const REFRESH_INTERVAL = 30000 // 30秒，定期刷新电量数据
58	
59	// 从本地存储读取电量数据
60	const loadBatteryData = () => {
61	  const storedLeftPower = uni.getStorageSync('leftPower')
62	  const storedRightPower = uni.getStorageSync('rightPower')
63	  const storedLeftModel = uni.getStorageSync('leftModel')
64	  const storedRightModel = uni.getStorageSync('rightModel')
65	  const storedLeftSerialNo = uni.getStorageSync('leftSerialNo')
66	  const storedRightSerialNo = uni.getStorageSync('rightSerialNo')
67	
68	  // 检查存储中是否有电量数据，包括 0
69	  if (storedLeftPower !== null && storedLeftPower !== undefined) {
70	    leftPower.value = storedLeftPower
71	  }
72	  if (storedRightPower !== null && storedRightPower !== undefined) {
73	    rightPower.value = storedRightPower
74	  }
75	
76	  // 检查存储中是否有设备信息
77	  if (storedLeftModel !== null && storedLeftModel !== undefined) {
78	    leftModel.value = storedLeftModel
79	  }
80	  if (storedRightModel !== null && storedRightModel !== undefined) {
81	    rightModel.value = storedRightModel
82	  }
83	  if (storedLeftSerialNo !== null && storedLeftSerialNo !== undefined) {
84	    leftSerialNo.value = storedLeftSerialNo
85	  }
86	  if (storedRightSerialNo !== null && storedRightSerialNo !== undefined) {
87	    rightSerialNo.value = storedRightSerialNo
88	  }
89	
90	  console.log('从本地存储中获取电量数据:', { storedLeftPower, storedRightPower })
91	  console.log('从本地存储中获取设备信息:', { storedLeftModel, storedRightModel, storedLeftSerialNo, storedRightSerialNo })
92	  console.log('当前电量数据 - 左耳:', leftPower.value, '右耳:', rightPower.value)
93	  console.log('当前设备信息 - 左耳型号:', leftModel.value, '右耳型号:', rightModel.value)
94	  console.log('当前设备信息 - 左耳SN号:', leftSerialNo.value, '右耳SN号:', rightSerialNo.value)
95	
96	  // 模拟连接状态
97	  leftConnected.value = leftPower.value > 0
98	  rightConnected.value = rightPower.value > 0
99	}
100	
101	// 启动定期刷新电量数据的定时器
102	const startRefreshTimer = () => {
103	  // 清除之前的定时器
104	  if (refreshTimer) {
105	    clearInterval(refreshTimer)
106	  }
107	  
108	  // 启动新的定时器
109	  refreshTimer = setInterval(() => {
110	    console.log('定期刷新电量数据...')
111	    loadBatteryData()
112	  }, REFRESH_INTERVAL) as unknown as number
113	  
114	  console.log('定期刷新电量数据的定时器已启动，间隔:', REFRESH_INTERVAL / 1000, '秒')
115	}
116	
117	// 清除定时器
118	const clearRefreshTimer = () => {
119	  if (refreshTimer) {
120	    clearInterval(refreshTimer)
121	    console.log('清除定期刷新电量数据的定时器')
122	  }
123	}
124	
125	// 监听本地存储变化（如果平台支持）
126	const setupStorageListener = () => {
127	  // 不同平台可能有不同的监听方法，这里使用通用的setInterval来模拟
128	  console.log('设置本地存储监听器')
129	}
130	
131	// 导航方法
132	const gotoTlInputScreen = () => {
133	  // 跳转到听力图输入页面
134	  uni.switchTab({ url: '/pages/hearing/hearing' })
135	}
136	
137	const gotoTlypScreen = () => {
138	  // 跳转到助听器验配页面
139	  uni.switchTab({ url: '/pages/fitting/fitting' })
140	}
141	
142	const gotoZtwtScreen = () => {
143	  // 跳转到助听器微调页面
144	  uni.switchTab({ url: '/pages/hearingAid/hearingAid' })
145	}
146	
147	onMounted(() => {
148	  loadBatteryData()
149	  startRefreshTimer()
150	  setupStorageListener()
151	})
152	
153	// 每次页面显示时都从本地存储读取最新的电量数据
154	onShow(() => {
155	  loadBatteryData()
156	  startRefreshTimer()
157	})
158	
159	// 页面卸载时清除定时器
160	onUnmounted(() => {
161	  clearRefreshTimer()
162	})
163	</script>
